import React from "react";
import Slider from "react-slick";
import "slick-carousel/slick/slick.css";
import "slick-carousel/slick/slick-theme.css";

// Dummy images (replace with real ones)
const images = [
  "https://unsplash.com/photos/a-woman-wears-traditional-fur-clothing-58XTfCD5_bw",
];

const ImageCarousel = () => {
  const settings = {
    dots: false,
    infinite: true,
    speed: 700,
    slidesToShow: 1,
    slidesToScroll: 1,
    autoplay: true,
    autoplaySpeed: 3000, // Change every 3 seconds
    arrows: true,
    accessibility: true, // ✅ Fix for ARIA warnings
    focusOnSelect: true,  // ✅ Allows proper focus handling
    pauseOnFocus: false,  // ✅ Prevents focus on hidden elements
  };

  return (
    <div className="w-full mx-auto mt-6">
      <Slider {...settings}>
        {images.map((img, index) => (
          <div key={index}>
            <img
              src={img}
              alt={`Slide ${index + 1}`}
              className="w-full h-[500px] object-cover rounded-lg"
            />
          </div>
        ))}
      </Slider>
    </div>
  );
};

export default ImageCarousel;
